def detect_smurfing(transactions):
    from collections import defaultdict
    user_trans = defaultdict(list)
    for t in transactions:
        user_trans[t['user_id']].append(t['amount'])

    for user_ids in user_trans.values():
        if len(user_ids) < 3:
            continue
        sorted_user = sorted(user_ids)
        small_threshold = sorted_user[-2] * 0.5
        count_small = sum(1 for t in user_ids if t < small_threshold)
        if count_small >= 3:
            return True
    return False
